static bool chk_bit (const BitArrayCL* ba, u16 idx) {
    if (ba == nullptr) {
        return false;
    }
    if (idx >= ba->get_count()) {
        return false;
    }
    return ba->get_bit(idx) == 1;
}

static bool chk_bank (const GeneralBitBank* bank, u16 city_idx, u16 flag_idx) {
    if (bank == nullptr) {
        return false;
    }
    return bank->is_flagged(city_idx, flag_idx);
}

static bool chk_resource (const AssessorCtx& ctx, u16 idx) {
    if (ctx.m_resource_bank != nullptr) {
        return chk_bank(ctx.m_resource_bank, ctx.m_city_idx, idx);
    }
    return chk_bit(ctx.m_resource, idx);
}

static bool chk_building (const AssessorCtx& ctx, u16 idx) {
    if (ctx.m_building_bank != nullptr) {
        return chk_bank(ctx.m_building_bank, ctx.m_city_idx, idx);
    }
    return chk_bit(ctx.m_building, idx);
}

static bool chk_city_flag (const AssessorCtx& ctx, u16 idx) {
    if (ctx.m_city_flag_bank != nullptr) {
        return chk_bank(ctx.m_city_flag_bank, ctx.m_city_idx, idx);
    }
    return chk_bit(ctx.m_city_flag, idx);
}

bool GeneralAssessor::chk (const ItemReqsStruct& reqs, const AssessorCtx& ctx) {
    for (u32 j = 0; j < MAX_PREREQ_COUNT; ++j) {
        const u8 tp = reqs.types[j];
        if (tp == ITEM_REQ_TYPE_NONE) {
            break;
        }
        const u16 ix = reqs.indices[j];
        if (ix == U16_KEY_NULL) {
            return false;
        }
        switch (tp) {
            case ITEM_REQ_TYPE_TECH:
                if (!chk_bit(ctx.m_tech, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_RESOURCE:
                if (!chk_resource(ctx, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_BUILDING:
                if (!chk_building(ctx, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_FLAG:
                if (!chk_city_flag(ctx, ix)) {
                    return false;
                }
                break;
            case ITEM_REQ_TYPE_CIV:
                if (!chk_bit(ctx.m_civ, ix)) {
                    return false;
                }
                break;
            default:
                return false;
        }
    }
    return true;
}

void GeneralAssessor::assess_building (BitArrayCL* out, u16 item_count, const BuildingStaticDataStruct* items, const AssessorCtx& ctx) {
    if (out == nullptr) {
        GAME_EXPECT(false, "GeneralAssessor assess_building out");
        return;
    }
    out->clear_all();
    if (items == nullptr) {
        GAME_EXPECT(false, "GeneralAssessor assess_building items");
        return;
    }
    for (u16 i = 0; i < item_count; ++i) {
        if (chk(items[i].reqs, ctx)) {
            out->set_bit(i);
        }
    }
}

